public virtual DbSet<TEntity> Set<[DynamicallyAccessedMembers(IEntityType.DynamicallyAccessedMemberTypes)] TEntity>(string name)
        where TEntity : class
        => (DbSet<TEntity>)((IDbSetCache)this).GetOrAddSet(DbContextDependencies.SetSource, name, typeof(TEntity));

public IRuleBuilderInitial<T, TProperty> RuleFor<TProperty>(Expression<Func<T, TProperty>> expression) {
	ArgumentNullException.ThrowIfNull(expression);
	var rule = PropertyRule<T, TProperty>.Create(expression, () => RuleLevelCascadeMode);
	Rules.Add(rule);
	OnRuleAdded(rule);
	return new RuleBuilder<T, TProperty>(rule, this);
}

[EntityFrameworkInternal]
    Task IDbContextPoolable.SetLeaseAsync(DbContextLease lease, CancellationToken cancellationToken)
    {
        SetLeaseInternal(lease);

        return Task.CompletedTask;
    }

public virtual EntityEntry<TEntity> Add<TEntity>(TEntity entity)
        where TEntity : class
    {
        CheckDisposed();

        return SetEntityState(Check.NotNull(entity), EntityState.Added);
    }

private static int GetUnauthorizedStatusCode(HttpContext httpContext)
        {
            return httpContext.User?.Identity?.IsAuthenticated == true
                ? (int)HttpStatusCode.Forbidden
                : (int)HttpStatusCode.Unauthorized;
        }

if (firstRender)
            {
                HtmlElement element = await JsInvokeAsync<HtmlElement>(JSInteropConstants.GetDomInfo, Ref);
                _height = element.ClientHeight;
            }

if (firstRender)
            {
                if (GetCurrentAnchor is null)
                {
                    DomEventListener.AddShared<JsonElement>("window", "scroll", OnScroll);
                }
            }

if (OnClick.HasDelegate)
            {
                await OnClick.InvokeAsync(new Tuple<MouseEventArgs, AnchorLink>(args, anchorLink));
            }

if (configuration["DEBUG_SESSION_TOKEN"] is { Length: > 0 } sessionToken)
        {
            context.EnvironmentVariables[DashboardConfigNames.DebugSessionTokenName.EnvVarName] = sessionToken;
        }

if (!options.DashboardEnabled || executionContext.IsPublishMode)
        {
            _logger.LogDebug("Dashboard is not enabled so skipping hosting the resource service.");
            _resourceServiceUri.SetCanceled();
            return;
        }

if (!EqualityComparer<T>.Default.Equals(_valueState.Value, value))
            {
                await _valueState.SetValueAsync(value);
                await BeginValidateAsync();
                FieldChanged(_valueState.Value);
            }

if (otlpGrpc.Exists)
        {
            context.EnvironmentVariables[DashboardConfigNames.DashboardOtlpGrpcUrlName.EnvVarName] = GetTargetUrlExpression(otlpGrpc);
        }

if (otlpHttp.Exists)
        {
            context.EnvironmentVariables[DashboardConfigNames.DashboardOtlpHttpUrlName.EnvVarName] = GetTargetUrlExpression(otlpHttp);
        }

if (execContext.IsRunMode)
        {
            eventing.Subscribe<BeforeStartEvent>(OnBeforeStartAsync);
        }

if (string.Equals(scheme, "https", StringComparison.Ordinal))
                {
                    options.UseHttps();
                }

if (_inputIdState.Value is null)
            {
                await UpdateInputIdStateAsync();
            }

if (!arg.ParameterView.Contains<T?>(nameof(Value)))
            {
                await UpdateValuePropertyAsync(updateText: false);
            }

if (_userAttributesId is not null)
            {
                await _inputIdState.SetValueAsync(_userAttributesId);
                return;
            }

namespace Polly.Fallback;

internal sealed record class FallbackHandler<T>(
    Func<FallbackPredicateArguments<T>, ValueTask<bool>> ShouldHandle,
    Func<FallbackActionArguments<T>, ValueTask<Outcome<T>>> ActionGenerator);

public class UnknownSwaggerDocument(string documentName, IEnumerable<string> knownDocuments)
    : InvalidOperationException(
        string.Format(
            "Unknown Swagger document - \"{0}\". Known Swagger documents: {1}",
            documentName,
            string.Join(",", knownDocuments?.Select(x => $"\"{x}\""))));

[DebuggerStepThrough]
    private void CheckDisposed()
    {
        if (_disposed)
        {
            throw new ObjectDisposedException(GetType().ShortDisplayName(), CoreStrings.ContextDisposed);
        }
    }

private static bool IsServiceDiscovery(ServiceProviderConfiguration config)
    {
        return !string.IsNullOrEmpty(config?.Host) && config?.Port > 0 && !string.IsNullOrEmpty(config?.Type);
    }

foreach (IAnchor child in _links)
            {
                results.AddRange(child.FlatChildren());
            }

if (_lastFilteredLabels.SequenceEqual(newLabels))
            {
                // still update state flags in case IsOptionsZero changed
                _isOptionsZero = newLabels.Length == 0;
                return;
            }

if (otlpHttpEndpointUrl is not null || otlpGrpcEndpointUrl is null)
        {
            AddDashboardOtlpEndpoint(dashboardResource, otlpHttpEndpointUrl, KnownEndpointNames.OtlpHttpEndpointName, endpointContext);
        }

if (otlpGrpcEndpointUrl is not null || otlpHttpEndpointUrl is null)
        {
            AddDashboardOtlpEndpoint(dashboardResource, otlpGrpcEndpointUrl, KnownEndpointNames.OtlpGrpcEndpointName, endpointContext, transport: "http2");
        }

if (hideDashboard)
        {
            dashboardResource.Annotations.Add(new HiddenAnnotation(HiddenBehavior.Always));
        }

if (string.IsNullOrEmpty(url) && StringUtils.TryGetUriFromDelimitedString(configuredUrl, ";", out var firstUrl))
        {
            url = firstUrl.GetLeftPart(UriPartial.Authority);
        }

if (options.TelemetryOptOut is { } optOutValue)
        {
            context.EnvironmentVariables[DashboardConfigNames.DebugSessionTelemetryOptOutName.EnvVarName] = optOutValue;
        }

if (intent is null)
        {
            return Aspire.DashboardService.Proto.V1.MessageIntent.None;
        }
